        "title": "简单 Agent 实现",
        "code": "# 简单 Agent 实现 (ReAct 风格)\nclass SimpleAgent:\n    def __init__(self, llm, tools):\n        self.llm = llm\n        self.tools = tools\n\n    def run(self, task):\n        \"\"\"Agent 主循环: Thought → Action → Observation\"\"\"\n        history = []\n        for step in range(10):\n            # 1. Thought\n            thought = self.llm.generate(f\"Task: {task}\\nHistory: {history}\\nThink:\")\n            \n            # 2. Action\n            if \"Final Answer\" in thought:\n                return thought.split(\"Final Answer:\")[1].strip()\n            \n            action, arg = self.parse_action(thought)\n            \n            # 3. Execute\n            result = self.tools[action](arg)\n            history.append(f\"Thought: {thought}\\nAction: {action}({arg})\\nResult: {result}\")\n\n        return \"No answer\"\n\nprint(\"=== Agent (ReAct) 核心循环 ===\")\nprint(\"1. Thought: 分析当前状态\")\nprint(\"2. Action: 选择工具\")\nprint(\"3. Execute: 执行工具\")\nprint(\"4. Observation: 观察结果\")\nprint(\"5. 循环直到得到答案\")",
