        "code": "# MemGPT 简化实现\nclass MemGPT:\n    def __init__(self, llm, vector_store, max_core=1000):\n        self.llm = llm\n        self.vector_store = vector_store\n        self.max_core = max_core  # 核心记忆容量\n\n    def recall(self, query):\n        \"\"\"检索记忆\"\"\"\n        results = self.vector_store.search(query, top_k=3)\n        return [r[\"content\"] for r in results]\n\n    def think(self, task, context):\n        \"\"\"思考: 动态加载记忆\"\"\"\n        # 1. 检索相关记忆\n        memory = self.recall(task)\n        \n        # 2. 构建 prompt\n        prompt = f\"Task: {task}\\nMemory: {memory}\\nContext: {context}\\nThink:\"\n        \n        # 3. 生成\n        thought = self.llm.generate(prompt)\n        \n        return thought\n\n    def remember(self, event):\n        \"\"\"存储记忆\"\"\"\n        if len(self.vector_store) > self.max_core:\n            # 核心记忆满, 存到外部\n            self.vector_store.add(event, store=\"external\")\n        else:\n            self.vector_store.add(event, store=\"core\")\n\nprint(\"=== MemGPT 记忆系统 ===\")\nprint(\"1. 核心记忆: 最重要的事实\")\nprint(\"2. 外部记忆: 向量库\")\nprint(\"3. 检索: 按相关性动态加���\")\nprint(\"4. 存储: 核心满则存外部\")",
