      "title": "七、真实工程案例 - 示例 1",
      "code": "import pandas as pd\nimport numpy as np\n\n# 模拟点击日志\nn = 100_000\ndf = pd.DataFrame({\n    'user_id': np.random.randint(0, 1000, n),\n    'item_id': np.random.randint(0, 5000, n),\n    'timestamp': pd.date_range('2023-01-01', periods=n, freq='min')\n})\n\n# 按用户和时间排序\ndf = df.sort_values(['user_id', 'timestamp'])\n\n# 过去 7 天点击次数\ndf['click_7d'] = df.groupby('user_id')['timestamp'].transform(\n    lambda x: x.rolling('7D', min_periods=1).count()\n)\n\n# 过去 30 天点击次数\ndf['click_30d'] = df.groupby('user_id')['timestamp'].transform(\n    lambda x: x.rolling('30D', min_periods=1).count()\n)\n\n# 最近点击的 item（滞后 1 期）\ndf['last_item'] = df.groupby('user_id')['item_id'].shift(1)\n\n# 用户点击序列的 item 嵌入均值\nuser_item_emb = np.random.randn(5000, 64)  # 预训练 item 嵌入\nuser_emb = df.groupby('user_id')['item_id'].apply(\n    lambda x: np.mean(user_item_emb[x.values], axis=0)\n)",
