      "title": "二、条件概率与贝叶斯定理 - 示例 2",
      "code": "from sklearn.feature_extraction.text import CountVectorizer\nfrom sklearn.naive_bayes import MultinomialNB\nfrom sklearn.pipeline import Pipeline\nfrom sklearn.datasets import fetch_20newsgroups\n\n# 加载数据（二分类子集）\ncategories = ['sci.space', 'rec.sport.baseball']\nnewsgroups_train = fetch_20newsgroups(subset='train', categories=categories)\nnewsgroups_test = fetch_20newsgroups(subset='test', categories=categories)\n\n# 构建pipeline：词袋模型 + 多项式朴素贝叶斯\npipeline = Pipeline([\n    ('vectorizer', CountVectorizer(stop_words='english')),\n    ('classifier', MultinomialNB(alpha=1.0))  # alpha=1拉普拉斯平滑\n])\n\n# 训练\npipeline.fit(newsgroups_train.data, newsgroups_train.target)\n\n# 预测\npredicted = pipeline.predict(newsgroups_test.data)\naccuracy = np.mean(predicted == newsgroups_test.target)\nprint(f\"朴素贝叶斯分类准确率: {accuracy:.4f}\")\n\n# 查看预测概率\nprobs = pipeline.predict_proba([\"The rocket launched into space\"])\nprint(f\"预测概率: {probs}\")",
