      "code": "class Pipeline:\n    def __init__(self):\n        self.steps = []\n\n    def add_step(self, step):\n        self.steps.append(step)\n\n    def execute(self, input_data):\n        data = input_data\n        for step in self.steps:\n            data = step(data)\n        return data\n\n# 使用示例\npipeline = Pipeline()\npipeline.add_step(query_rewriter)\npipeline.add_step(retriever)\npipeline.add_step(reranker)\npipeline.add_step(generator)\n\nfinal_answer = pipeline.execute(\"用户原始查询\")",
