      "title": "代码示例 6",
      "code": "# 伪代码，省略了并行执行细节\nclass DAG:\n    def __init__(self):\n        self.nodes = {}  # node_name -> node_object\n        self.edges = {}  # node_name -> list of upstream node names\n\n    def add_node(self, name, func, upstream_names=[]):\n        self.nodes[name] = func\n        self.edges[name] = upstream_names\n\n    def execute(self, start_input):\n        results = {}\n        # 拓扑排序\n        sorted_nodes = topological_sort(self.edges)\n        for node_name in sorted_nodes:\n            # 获取上游结果\n            upstream_results = [results[up] for up in self.edges[node_name]]\n            # 执行节点\n            results[node_name] = self.nodes[node_name](upstream_results)\n        return results",
