      "code": "# RAGAS Faithfulness 评估示例\nfrom ragas.metrics import faithfulness\nfrom ragas.llms import LangchainLLM\nfrom langchain_openai import ChatOpenAI\nimport os\n\n# 初始化 LLM\nos.environ[\"OPENAI_API_KEY\"] = \"your-api-key\"\nllm = ChatOpenAI(model=\"gpt-4\", temperature=0)\n\n# 创建评估器\nfaithfulness_scorer = faithfulness(llm=llm)\n\n# 示例数据\nquestion = \"爱因斯坦在什么时候提出了相对论？\"\ncontexts = [\"爱因斯坦于 1905 年提出了狭义相对论。\"]\nanswer = \"爱因斯坦在 1905 年提出了相对论。\"\n\n# 评估\nresult = faithfulness_scorer.score(\n    question=question,\n    contexts=contexts,\n    answer=answer\n)\nprint(f\"Faithfulness Score: {result}\")  # 输出接近 1.0",
